    '''Transfer A→B: lock A first, then B.'''  

    def step_lock_a():  
        acquire("A")  
        return "locked_A"  

    def step_lock_b_and_transfer():  
        acquire("B")  
        _state["A"] -= amount  
        _state["B"] += amount  
        release("B")  
        release("A")  
        return "transferred_a_to_b"  

    return step_lock_a, step_lock_b_and_transfer  


def make_transfer_b_to_a_steps(amount):  
    '''Transfer B→A: FIXED — locks A first, then B (same order).'''  

    def step_lock_a():  
        acquire("A")  
        return "locked_A"  

    def step_lock_b_and_transfer():  
        acquire("B")  
        _state["B"] -= amount  
        _state["A"] += amount  
        release("B")  
        release("A")  
        return "transferred_b_to_a"  

    return step_lock_a, step_lock_b_and_transfer  


def sequential_transfers():  
    '''A→B then B→A. Sequential: works fine.'''  
    reset()  
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)  
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)  
    run_steps([  
        (lock_ab, ()), (do_ab, ()),  
        (lock_ba, ()), (do_ba, ()),  
    ])  
    return get_state()  


def interleaved_transfers():  
    '''A→B and B→A interleaved: NO LONGER DEADLOCK.'''  
    reset()  
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)  
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)  
    try:  
        run_steps([  
            (lock_ab, ()),   # A→B locks A  
            (lock_ba, ()),   # B→A locks A  
            (do_ab, ()),     # A→B transfers  
            (do_ba, ()),     # B→A transfers  
        ])  
        return get_state()  
    except RuntimeError as e:  
        return {"error": str(e)}"
  }
